local TD = TD.td1madao["ydj_dst_td1madao"] local CONST = TD.CONST local chineseLanguage = GetModConfigData("ChineseLanguage") or 0 if chineseLanguage == 1 then     CONST.IS_CHINESE = true     td1madoImport("td1madao/language/td1madao_%s_global_language_ch.lua") elseif chineseLanguage == 2 then     CONST.IS_CHINESE = false     td1madoImport("td1madao/language/td1madao_%s_global_language_en.lua") else     CONST.AUTO_TRANSLATE = true     td1madoImport("td1madao/language/td1madao_%s_global_language_en.lua") end AddTd1madaoLifecyclePostInit(function()     if (CONST.AUTO_TRANSLATE and TD.isCh()) or CONST.IS_CHINESE then         td1madoImport("td1madao/language/td1madao_%s_global_language_ch.lua")     end end) if TD.ds() then     local stop = false     local old = _G.LanguageTranslator.ConvertEscapeCharactersToRaw     if old then         _G.LanguageTranslator.ConvertEscapeCharactersToRaw = function(self, str, ...)             local data = old(self, str, ...)             if not stop and string.upper(STRINGS.NAMES.GRASS) ~= string.upper("Grass") then                 td1madoImport("td1madao/language/td1madao_%s_global_language_ch.lua")                 stop = true             end             return data         end     end end 